import React, { useState, useEffect } from 'react';
import { useProducts } from './ProductContext';
import { useNavigate } from 'react-router-dom';
import { Mail, Lock, ShieldCheck, UserPlus, Trash2, Save } from 'lucide-react';

const Admin = () => {
  const { staff, addStaff, deleteStaff, user, updateUser } = useProducts();
  const navigate = useNavigate();

  // Profil sozlamalari state
  const [profileData, setProfileData] = useState({
    email: '',
    password: '',
    role: ''
  });

  // Xodim qo'shish state
  const [newEmail, setNewEmail] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    if (user) {
      setProfileData({
        email: user.email || '',
        password: user.password || '',
        role: user.role || ''
      });
    }
  }, [user]);

  const handleProfileSave = (e) => {
    e.preventDefault();

    // Validatsiya
    if (!profileData.email.includes('@')) {
      alert('Iltimos, to\'g\'ri Gmail manzilini kiriting!');
      return;
    }
    if (profileData.password.length < 6) {
      alert('Parol kamida 6 ta belgidan iborat bo\'lishi kerak!');
      return;
    }

    // Update Context and LocalStorage
    updateUser(profileData);

    alert('Profil ma\'lumotlari muvaffaqiyatli yangilandi!');

    // Redirect if role changed to staff
    if (profileData.role === 'staff') {
      navigate('/products');
    }
  };

  const handleAddStaffSubmit = (e) => {
    e.preventDefault();
    if (newEmail && newPassword) {
      const success = addStaff(newEmail, newPassword);
      if (success) {
        setNewEmail('');
        setNewPassword('');
        setShowForm(false);
      }
    }
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-10">
      {/* 1. Profil Sozlamalari Bloki */}
      <div className="bg-white rounded-[2.5rem] p-8 shadow-md border border-gray-50 animate-in fade-in slide-in-from-top duration-500">
        <div className="flex items-center gap-4 mb-8">
          <div className="p-3 bg-purple-100 rounded-2xl text-purple-700">
            <ShieldCheck className="w-8 h-8" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-900">Profil sozlamalari</h2>
            <p className="text-gray-500">Shaxsiy ma'lumotlaringizni boshqaring</p>
          </div>
        </div>

        <form onSubmit={handleProfileSave} className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-600 flex items-center gap-2 px-1">
              <Mail className="w-4 h-4" /> Gmail (Email)
            </label>
            <input
              type="email"
              value={profileData.email}
              onChange={(e) => setProfileData({...profileData, email: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold shadow-sm transition-all"
              placeholder="admin@gmail.com"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-600 flex items-center gap-2 px-1">
              <Lock className="w-4 h-4" /> Yangi parol
            </label>
            <input
              type="password"
              value={profileData.password}
              onChange={(e) => setProfileData({...profileData, password: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold shadow-sm transition-all"
              placeholder="******"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-gray-600 flex items-center gap-2 px-1">
              <ShieldCheck className="w-4 h-4" /> Rolni tanlang
            </label>
            <select
              value={profileData.role}
              onChange={(e) => setProfileData({...profileData, role: e.target.value})}
              className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-200 font-bold shadow-sm transition-all appearance-none cursor-pointer"
            >
              <option value="admin">Glavniy Admin</option>
              <option value="staff">Staff (Xodim)</option>
            </select>
          </div>
          <div className="md:col-span-3 flex justify-end mt-2">
            <button
              type="submit"
              className="flex items-center gap-2 bg-purple-700 text-white px-8 py-4 rounded-2xl font-black text-lg hover:bg-purple-800 shadow-lg shadow-purple-200 active:scale-95 transition-all"
            >
              <Save className="w-6 h-6" /> O'zgarishlarni saqlash
            </button>
          </div>
        </form>
      </div>

      <hr className="border-gray-100" />

      {/* 2. Xodimlarni Boshqarish Bloki */}
      <div>
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-100 rounded-2xl text-blue-700">
              <UserPlus className="w-8 h-8" />
            </div>
            <h1 className="text-2xl font-black text-gray-900">Xodimlarni boshqarish</h1>
          </div>
          <button
            onClick={() => setShowForm(!showForm)}
            className={`px-6 py-3 rounded-2xl font-bold flex items-center gap-2 shadow-md transition-all active:scale-95 ${
              showForm ? 'bg-gray-100 text-gray-600' : 'bg-blue-600 text-white hover:bg-blue-700'
            }`}
          >
            {showForm ? 'Yopish' : 'Yangi xodim qo\'shish'}
          </button>
        </div>

        {showForm && (
          <form onSubmit={handleAddStaffSubmit} className="bg-white p-8 rounded-[2.5rem] shadow-md mb-8 border border-gray-50 animate-in zoom-in duration-300">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-bold text-gray-600 px-1">Gmail (Email)</label>
                <input
                  type="email"
                  required
                  value={newEmail}
                  onChange={(e) => setNewEmail(e.target.value)}
                  className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-200 font-bold"
                  placeholder="xodim@gmail.com"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-bold text-gray-600 px-1">Parol</label>
                <input
                  type="password"
                  required
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full px-5 py-4 bg-slate-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-200 font-bold"
                  placeholder="******"
                />
              </div>
            </div>
            <button
              type="submit"
              className="mt-6 w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg hover:bg-blue-700 shadow-lg shadow-blue-100 transition-all"
            >
              Saqlash
            </button>
          </form>
        )}

        <div className="bg-white rounded-[2.5rem] shadow-md overflow-hidden border border-gray-50">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-gray-100">
              <tr>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest">Email</th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest">Rol</th>
                <th className="px-8 py-5 text-xs font-black text-gray-400 uppercase tracking-widest text-right">Amallar</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {staff.length === 0 ? (
                <tr>
                  <td colSpan="3" className="px-8 py-10 text-center text-gray-400 font-bold">Xodimlar mavjud emas</td>
                </tr>
              ) : (
                staff.map((member) => (
                  <tr key={member.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-8 py-5 font-bold text-gray-700">{member.email}</td>
                    <td className="px-8 py-5">
                      <span className="px-4 py-1.5 bg-blue-50 text-blue-700 rounded-full text-xs font-black uppercase tracking-tighter">
                        {member.role}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <button
                        onClick={() => deleteStaff(member.id)}
                        className="text-gray-300 hover:text-red-600 transition-colors p-2"
                        title="O'chirish"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Admin;
